import{j as e}from"./vendor-react-Cam-V6TZ.js";import{u as s,A as n,H as u,F as c}from"./public-shell-DV_oYWa7.js";import"./styles-DHQkNmKf.js";const d={oferta:{slug:"oferta",title:{uk:"Публічна оферта",en:"Public Offer"},updatedAt:{uk:"31 травня 2026 року",en:"May 31, 2026"},intro:{uk:"Ця Публічна оферта визначає умови оформлення, оплати, виготовлення, доставки та отримання замовлень на сайті Aurora Atelier.",en:"This Public Offer sets out the terms for ordering, payment, production, delivery, and receipt of orders placed through the Aurora Atelier website."},outro:{uk:"Оформлюючи замовлення на сайті, клієнт підтверджує, що ознайомився з умовами цієї Публічної оферти та приймає їх у повному обсязі.",en:"By placing an order on the website, the customer confirms that they have reviewed this Public Offer and accept its terms in full."},sections:{uk:[{title:"1. Загальні положення",paragraphs:["1.1. Aurora Atelier — це онлайн-вітрина ювелірної майстерні, де клієнт може обрати готову прикрасу з каталогу або створити індивідуально налаштовану прикрасу за допомогою конструктора.","1.2. Ця Публічна оферта є пропозицією укласти електронний договір купівлі-продажу товару або замовлення персоналізованого виробу.","1.3. Акцептом цієї оферти є оформлення замовлення на сайті та підтвердження згоди з умовами оферти під час оформлення замовлення.","1.4. Умови цієї оферти застосовуються до всіх замовлень, оформлених через сайт Aurora Atelier."]},{title:"2. Терміни",paragraphs:["2.1. Сайт — вебсистема Aurora Atelier, призначена для перегляду каталогу, створення персоналізованих прикрас, додавання товарів до кошика та оформлення замовлень.","2.2. Клієнт — фізична особа, яка переглядає товари, додає їх до кошика або оформлює замовлення на сайті.","2.3. Готова прикраса — товар із каталогу Aurora Atelier, що має визначені характеристики та може бути доданий до кошика без індивідуального налаштування.","2.4. Персоналізована прикраса — прикраса, створена або змінена за індивідуальними параметрами клієнта, зокрема через конструктор, вибір металу, каменю, розміру, гравіювання або іншої конфігурації.","2.5. Замовлення — оформлений клієнтом запит на придбання готової прикраси або виготовлення персоналізованої прикраси."]},{title:"3. Предмет договору",paragraphs:["3.1. Aurora Atelier надає клієнту можливість обрати готову прикрасу з каталогу або сформувати індивідуальну конфігурацію прикраси за допомогою конструктора.","3.2. Клієнт самостійно обирає товар, параметри прикраси, кількість, спосіб отримання та контактні дані для оформлення замовлення.","3.3. Після оформлення замовлення Aurora Atelier отримує дані замовлення та обробляє його відповідно до обраних параметрів."]},{title:"4. Оформлення замовлення",paragraphs:["4.1. Для оформлення замовлення клієнт додає товар або персоналізовану прикрасу до кошика, заповнює контактні дані та підтверджує замовлення.","4.2. Перед підтвердженням замовлення клієнт зобов’язаний перевірити склад кошика, кількість товарів, обрані параметри прикраси, розмір, матеріал, камінь, гравіювання та інші характеристики.","4.3. Після оформлення замовлення клієнт отримує підтвердження замовлення на сайті або через контактні дані, зазначені під час оформлення.","4.4. Якщо в замовленні виявлено помилку, клієнт має звернутися до Aurora Atelier якомога швидше до початку обробки або виготовлення замовлення."]},{title:"5. Персоналізовані прикраси",paragraphs:["5.1. Персоналізованою вважається прикраса, створена або налаштована відповідно до індивідуальних параметрів клієнта.","5.2. До персоналізованих прикрас належать вироби, створені через конструктор, вироби з індивідуальним вибором металу, каменю, розміру, гравіювання або іншої конфігурації.","5.3. Клієнт підтверджує, що перед оформленням замовлення перевірив усі параметри персоналізованої прикраси.","5.4. Після початку обробки або виготовлення персоналізованого замовлення зміна параметрів може бути обмежена або неможлива.","5.5. Умови повернення персоналізованих прикрас визначаються цією офертою та сторінкою “Повернення та обмін”."]},{title:"6. Ціни та оплата",paragraphs:["6.1. Ціни на сайті зазначаються у гривнях.","6.2. Вартість готової прикраси визначається відповідно до ціни, вказаної в каталозі.","6.3. Вартість персоналізованої прикраси може залежати від обраного типу виробу, металу, каменю, розміру, додаткових параметрів та комплектації.","6.4. Остаточна вартість замовлення відображається в кошику перед підтвердженням замовлення.","6.5. Оплата здійснюється доступним на сайті способом. Якщо на сайті реалізовано тестовий або демонстраційний режим оплати, це має бути зазначено в інтерфейсі проєкту."]},{title:"7. Доставка та отримання",paragraphs:["7.1. Умови доставки залежать від обраного способу отримання, міста та служби доставки.","7.2. Орієнтовні строки доставки або виготовлення можуть відображатися на сайті або уточнюватися після оформлення замовлення.","7.3. Для персоналізованих прикрас строк виконання може бути довшим, оскільки виріб створюється за індивідуальними параметрами клієнта.","7.4. Aurora Atelier не несе відповідальності за затримки, спричинені службою доставки, якщо замовлення було своєчасно передано перевізнику."]},{title:"8. Якість, гарантія та догляд",paragraphs:["8.1. Aurora Atelier прагне передавати клієнтам прикраси належної якості, що відповідають опису товару або погодженим параметрам персоналізованого замовлення.","8.2. Клієнт має право звернутися щодо якості виробу, якщо виявлено дефект, пошкодження або невідповідність замовленню.","8.3. Гарантійні звернення розглядаються індивідуально з урахуванням характеру виробу, умов експлуатації та причини звернення.","8.4. Гарантія не поширюється на пошкодження, спричинені неправильним використанням, механічним впливом, контактом із агресивними речовинами або порушенням рекомендацій з догляду."]},{title:"9. Повернення та обмін",paragraphs:["9.1. Умови повернення та обміну описані на сторінці “Повернення та обмін”.","9.2. Готові прикраси можуть бути повернуті або обміняні відповідно до умов, зазначених на сайті та вимог законодавства України.","9.3. Персоналізовані прикраси, виготовлені за індивідуальними параметрами клієнта, не підлягають стандартному поверненню як товар належної якості, якщо вони не мають дефектів або невідповідностей з боку Aurora Atelier.","9.4. Якщо виріб має дефект, пошкодження або не відповідає погодженим параметрам замовлення з вини Aurora Atelier, звернення клієнта розглядається індивідуально."]},{title:"10. Персональні дані",paragraphs:["10.1. Під час оформлення замовлення Aurora Atelier обробляє персональні дані клієнта, необхідні для прийняття, обробки та виконання замовлення.","10.2. До таких даних можуть належати ім’я, номер телефону, електронна пошта, адреса доставки та інформація про склад замовлення.","10.3. Детальні умови обробки персональних даних описані на сторінці “Політика конфіденційності”."]},{title:"11. Відповідальність сторін",paragraphs:["11.1. Клієнт відповідає за правильність даних, зазначених під час оформлення замовлення.","11.2. Aurora Atelier не несе відповідальності за неможливість виконання замовлення, якщо клієнт надав неправильні контактні дані або не відповідає на повідомлення щодо уточнення замовлення.","11.3. Aurora Atelier не несе відповідальності за відмінності у відтінках матеріалів або каменів, що можуть виникати через налаштування екрана клієнта, освітлення або особливості візуалізації товару на сайті."]},{title:"12. Зміни до оферти",paragraphs:["12.1. Aurora Atelier може оновлювати умови цієї Публічної оферти.","12.2. Актуальна редакція оферти завжди розміщується на цій сторінці.","12.3. До замовлення застосовуються умови оферти, чинні на момент оформлення замовлення."]},{title:"13. Контакти",paragraphs:["З питань оформлення замовлення, повернення, обміну або обробки персональних даних клієнт може звернутися до Aurora Atelier через контактні дані, зазначені на сайті."],contacts:["Електронна пошта: auroraatelier.mail@gmail.com","Телефон: +38 (099) 000-00-00","Адреса майстерні: м. Харків, вул. Сумська, 10, ТЦ Ave Plaza"]}],en:[{title:"1. General provisions",paragraphs:["1.1. Aurora Atelier is an online storefront of a jewelry atelier where a customer may choose a finished piece from the catalog or create a personalized piece with the constructor.","1.2. This Public Offer is an offer to conclude an electronic contract for the sale of goods or for the ordering of a personalized item.","1.3. Acceptance of this offer takes place when the customer places an order on the website and confirms agreement with the offer terms during checkout.","1.4. The terms of this offer apply to all orders placed through the Aurora Atelier website."]},{title:"2. Definitions",paragraphs:["2.1. Website means the Aurora Atelier web system intended for catalog browsing, creation of personalized jewelry, adding items to the cart, and order placement.","2.2. Customer means an individual who browses products, adds them to the cart, or places an order on the website.","2.3. Finished piece means a catalog product with predefined characteristics that can be added to the cart without individual customization.","2.4. Personalized piece means a piece created or modified according to the customer's individual parameters, including through the constructor, selection of metal, stone, size, engraving, or other configuration.","2.5. Order means a request placed by the customer to purchase a finished piece or to manufacture a personalized piece."]},{title:"3. Subject of the contract",paragraphs:["3.1. Aurora Atelier enables the customer to choose a finished piece from the catalog or to form an individual jewelry configuration using the constructor.","3.2. The customer independently chooses the product, jewelry parameters, quantity, delivery method, and contact details required for order placement.","3.3. After the order is placed, Aurora Atelier receives the order data and processes it according to the selected parameters."]},{title:"4. Order placement",paragraphs:["4.1. To place an order, the customer adds a product or personalized piece to the cart, fills in contact details, and confirms the order.","4.2. Before confirming the order, the customer must review the cart contents, item quantities, selected jewelry parameters, size, material, stone, engraving, and any other characteristics.","4.3. After order placement, the customer receives order confirmation on the website or via the contact details provided during checkout.","4.4. If an error is discovered in the order, the customer should contact Aurora Atelier as soon as possible before processing or production begins."]},{title:"5. Personalized pieces",paragraphs:["5.1. A piece is considered personalized if it is created or configured according to the customer's individual parameters.","5.2. Personalized pieces include pieces created through the constructor as well as pieces with an individual selection of metal, stone, size, engraving, or other configuration.","5.3. The customer confirms that all parameters of the personalized piece have been reviewed before the order is placed.","5.4. Once processing or manufacturing of a personalized order has started, changing the parameters may be limited or impossible.","5.5. Return conditions for personalized pieces are determined by this offer and by the “Returns & exchanges” page."]},{title:"6. Prices and payment",paragraphs:["6.1. Prices on the website are shown in hryvnias.","6.2. The cost of a finished piece is determined by the price shown in the catalog.","6.3. The cost of a personalized piece may depend on the selected product type, metal, stone, size, additional parameters, and configuration.","6.4. The final order price is shown in the cart before the order is confirmed.","6.5. Payment is made using the method available on the website. If the website uses a test or demo payment flow, this must be indicated in the project interface."]},{title:"7. Delivery and receipt",paragraphs:["7.1. Delivery terms depend on the selected delivery method, city, and carrier.","7.2. Approximate delivery or production timeframes may be shown on the website or clarified after the order is placed.","7.3. Personalized pieces may require a longer fulfillment period because the piece is made according to the customer's individual parameters.","7.4. Aurora Atelier is not responsible for delays caused by the delivery service if the order was transferred to the carrier on time."]},{title:"8. Quality, warranty, and care",paragraphs:["8.1. Aurora Atelier aims to deliver pieces of proper quality that correspond to the product description or to the agreed parameters of the personalized order.","8.2. The customer may contact Aurora Atelier regarding the quality of a piece if a defect, damage, or mismatch with the order is discovered.","8.3. Warranty claims are reviewed individually with regard to the nature of the piece, conditions of use, and the reason for the claim.","8.4. The warranty does not cover damage caused by improper use, mechanical impact, contact with aggressive substances, or failure to follow care recommendations."]},{title:"9. Returns and exchanges",paragraphs:["9.1. Return and exchange conditions are described on the “Returns & exchanges” page.","9.2. Finished pieces may be returned or exchanged according to the terms stated on the website and the requirements of Ukrainian law.","9.3. Personalized pieces manufactured according to the customer's individual parameters are not subject to a standard return as goods of proper quality if they do not have defects or mismatches caused by Aurora Atelier.","9.4. If a piece has a defect, damage, or does not correspond to the agreed order parameters due to Aurora Atelier's fault, the customer's request is reviewed individually."]},{title:"10. Personal data",paragraphs:["10.1. When an order is placed, Aurora Atelier processes the customer's personal data required to receive, process, and fulfill the order.","10.2. Such data may include the customer's name, phone number, email address, delivery address, and information about the order contents.","10.3. Detailed terms of personal data processing are described on the “Privacy policy” page."]},{title:"11. Liability of the parties",paragraphs:["11.1. The customer is responsible for the accuracy of the data provided when placing an order.","11.2. Aurora Atelier is not responsible for the inability to fulfill an order if the customer provided incorrect contact details or does not respond to requests for clarification of the order.","11.3. Aurora Atelier is not responsible for differences in shades of materials or stones that may occur due to screen settings, lighting, or the specifics of product visualization on the website."]},{title:"12. Changes to the offer",paragraphs:["12.1. Aurora Atelier may update the terms of this Public Offer.","12.2. The current version of the offer is always published on this page.","12.3. The version of the offer effective at the time the order is placed applies to the order."]},{title:"13. Contacts",paragraphs:["For questions about order placement, returns, exchanges, or personal data processing, the customer may contact Aurora Atelier using the contact details indicated on the website."],contacts:["Email: auroraatelier.mail@gmail.com","Phone: +38 (099) 000-00-00","Atelier address: Kharkiv, 10 Sumska Street, Ave Plaza"]}]}},returns:{slug:"returns",title:{uk:"Повернення та обмін",en:"Returns & Exchanges"},updatedAt:{uk:"31 травня 2026 року",en:"May 31, 2026"},intro:{uk:"Ця сторінка описує умови повернення та обміну готових і персоналізованих прикрас, оформлених на сайті Aurora Atelier.",en:"This page describes the conditions for returning and exchanging finished and personalized pieces ordered through the Aurora Atelier website."},sections:{uk:[{title:"1. Загальні умови",paragraphs:["1.1. Клієнт може звернутися щодо повернення, обміну або перевірки якості виробу через контактні дані, зазначені на сайті.","1.2. Звернення розглядається після отримання інформації про замовлення: номера замовлення, контактних даних клієнта, опису ситуації та, за потреби, фото виробу.","1.3. Повернення або обмін можливі лише за умови, що звернення відповідає умовам цієї сторінки та вимогам законодавства України."]},{title:"2. Готові прикраси",paragraphs:["2.1. Готовою прикрасою вважається виріб із каталогу Aurora Atelier, який не був змінений або виготовлений за індивідуальними параметрами клієнта.","2.2. Якщо готова прикраса не використовувалась, збережено її товарний вигляд, споживчі властивості, пакування та документ, що підтверджує замовлення, клієнт може звернутися щодо повернення або обміну протягом 14 днів з моменту отримання замовлення.","2.3. Повернення коштів здійснюється після отримання та перевірки виробу.","2.4. Витрати на доставку при поверненні товару належної якості можуть покладатися на клієнта, якщо інше не погоджено з Aurora Atelier."]},{title:"3. Персоналізовані прикраси",paragraphs:["3.1. Персоналізованою прикрасою вважається виріб, створений або змінений за індивідуальними параметрами клієнта.","3.2. До персоналізованих прикрас належать вироби, створені через конструктор, вироби з обраним металом, каменем, розміром, гравіюванням, індивідуальною комплектацією або іншими параметрами, визначеними клієнтом.","3.3. Персоналізовані прикраси виготовляються під конкретне замовлення клієнта, тому не підлягають стандартному поверненню або обміну як товар належної якості, якщо виріб відповідає погодженим параметрам і не має дефектів.","3.4. Перед підтвердженням замовлення клієнт має уважно перевірити всі параметри персоналізованої прикраси: тип виробу, матеріал, камінь, розмір, гравіювання та інші налаштування."]},{title:"4. Ювелірні вироби належної якості",paragraphs:["4.1. Звертаємо увагу, що окремі категорії ювелірних виробів належної якості можуть не підлягати обміну або поверненню відповідно до законодавства України.","4.2. Якщо клієнт має сумніви щодо можливості повернення конкретного виробу, рекомендуємо звернутися до Aurora Atelier до оформлення замовлення."]},{title:"5. Якщо виріб має дефект або невідповідність",paragraphs:["5.1. Якщо клієнт отримав виріб із дефектом, пошкодженням або невідповідністю погодженим параметрам замовлення, необхідно звернутися до Aurora Atelier якомога швидше після отримання замовлення.","5.2. У зверненні потрібно вказати номер замовлення, опис проблеми та додати фото або відео, що демонструють дефект або невідповідність.","5.3. Якщо дефект або невідповідність виникли з вини Aurora Atelier, звернення розглядається індивідуально. Можливими рішеннями можуть бути ремонт, заміна, корекція виробу або повернення коштів.","5.4. Персоналізований характер виробу не обмежує права клієнта у випадку дефекту, пошкодження або помилки з боку Aurora Atelier."]},{title:"6. Умови, за яких повернення або обмін можуть бути відхилені",list:["виріб має сліди використання;","пошкодження виникло після отримання замовлення клієнтом;","виріб був пошкоджений через неправильний догляд, механічний вплив або контакт із речовинами, які можуть вплинути на стан металу чи каменів;","персоналізований виріб відповідає погодженим параметрам і не має дефектів;","відсутні дані, що дозволяють ідентифікувати замовлення."]},{title:"7. Як оформити звернення",paragraphs:["Щоб звернутися щодо повернення, обміну або перевірки якості, напишіть нам через контактні дані, зазначені на сайті."],list:["ім’я та контактні дані;","номер замовлення;","назву виробу;","причину звернення;","фото або відео виробу, якщо звернення стосується дефекту чи пошкодження."]},{title:"8. Строк розгляду звернення",paragraphs:["8.1. Aurora Atelier розглядає звернення після отримання всієї необхідної інформації від клієнта.","8.2. Якщо для розгляду потрібно отримати виріб назад, рішення приймається після огляду виробу.","8.3. Остаточне рішення повідомляється клієнту через контактні дані, зазначені у зверненні."]},{title:"9. Контакти",paragraphs:["З питань повернення, обміну або якості виробу клієнт може звернутися до Aurora Atelier."],contacts:["Електронна пошта: auroraatelier.mail@gmail.com","Телефон: +38 (099) 000-00-00","Адреса майстерні: м. Харків, вул. Сумська, 10, ТЦ Ave Plaza"]}],en:[{title:"1. General conditions",paragraphs:["1.1. The customer may contact Aurora Atelier regarding a return, exchange, or quality review of a piece using the contact details provided on the website.","1.2. A request is reviewed after Aurora Atelier receives order information, including the order number, the customer's contact details, a description of the situation, and, if needed, photos of the piece.","1.3. A return or exchange is possible only if the request complies with the terms of this page and the requirements of Ukrainian law."]},{title:"2. Finished pieces",paragraphs:["2.1. A finished piece is a product from the Aurora Atelier catalog that has not been changed or manufactured according to the customer's individual parameters.","2.2. If a finished piece has not been used and its marketable condition, consumer properties, packaging, and the document confirming the order have been preserved, the customer may request a return or exchange within 14 days of receiving the order.","2.3. Refunds are made after the piece is received and inspected.","2.4. Delivery costs for returning goods of proper quality may be borne by the customer unless otherwise agreed with Aurora Atelier."]},{title:"3. Personalized pieces",paragraphs:["3.1. A piece is considered personalized if it is created or modified according to the customer's individual parameters.","3.2. Personalized pieces include pieces created through the constructor as well as pieces with a selected metal, stone, size, engraving, individual configuration, or other customer-defined parameters.","3.3. Personalized pieces are manufactured for a specific customer order and therefore are not subject to a standard return or exchange as goods of proper quality if the piece matches the agreed parameters and has no defects.","3.4. Before confirming an order, the customer must carefully review all parameters of the personalized piece, including the product type, material, stone, size, engraving, and other settings."]},{title:"4. Jewelry goods of proper quality",paragraphs:["4.1. Please note that certain categories of jewelry goods of proper quality may not be subject to exchange or return under Ukrainian law.","4.2. If the customer has doubts about the possibility of returning a specific piece, Aurora Atelier recommends contacting the atelier before placing the order."]},{title:"5. If the piece has a defect or mismatch",paragraphs:["5.1. If the customer receives a piece with a defect, damage, or a mismatch with the agreed order parameters, Aurora Atelier should be contacted as soon as possible after the order is received.","5.2. The request must specify the order number, a description of the issue, and include photos or video demonstrating the defect or mismatch.","5.3. If the defect or mismatch arose due to Aurora Atelier's fault, the request is reviewed individually. Possible solutions may include repair, replacement, correction of the piece, or a refund.","5.4. The personalized nature of a piece does not limit the customer's rights in the event of a defect, damage, or mistake on Aurora Atelier's side."]},{title:"6. Conditions under which a return or exchange may be refused",list:["the piece shows signs of use;","the damage occurred after the order was received by the customer;","the piece was damaged due to improper care, mechanical impact, or contact with substances that may affect the condition of the metal or stones;","the personalized piece matches the agreed parameters and has no defects;","there is not enough data to identify the order."]},{title:"7. How to submit a request",paragraphs:["To submit a request for a return, exchange, or quality review, contact Aurora Atelier using the contact details provided on the website."],list:["name and contact details;","order number;","product name;","reason for the request;","photos or video of the piece if the request concerns a defect or damage."]},{title:"8. Review period",paragraphs:["8.1. Aurora Atelier reviews a request after receiving all information required from the customer.","8.2. If the piece must be returned for review, a decision is made after the piece is inspected.","8.3. The final decision is communicated to the customer using the contact details specified in the request."]},{title:"9. Contacts",paragraphs:["For questions about returns, exchanges, or product quality, the customer may contact Aurora Atelier."],contacts:["Email: auroraatelier.mail@gmail.com","Phone: +38 (099) 000-00-00","Atelier address: Kharkiv, 10 Sumska Street, Ave Plaza"]}]}},privacyPolicy:{slug:"privacy-policy",title:{uk:"Політика конфіденційності",en:"Privacy Policy"},updatedAt:{uk:"31 травня 2026 року",en:"May 31, 2026"},intro:{uk:"Ця Політика конфіденційності пояснює, які персональні дані може обробляти Aurora Atelier, з якою метою вони використовуються та як клієнт може звернутися щодо своїх даних.",en:"This Privacy Policy explains what personal data Aurora Atelier may process, for what purposes it is used, and how a customer may contact Aurora Atelier regarding their data."},sections:{uk:[{title:"1. Загальні положення",paragraphs:["1.1. Aurora Atelier поважає приватність клієнтів і обробляє персональні дані лише в обсязі, необхідному для роботи сайту, оформлення замовлень, зв’язку з клієнтом та виконання замовлень.","1.2. Користуючись сайтом та оформлюючи замовлення, клієнт погоджується з умовами цієї Політики конфіденційності.","1.3. Ця Політика застосовується до даних, які клієнт надає під час використання сайту, реєстрації, оформлення замовлення або звернення до Aurora Atelier."]},{title:"2. Які дані ми можемо збирати",paragraphs:["Aurora Atelier може обробляти такі дані:"],list:["ім’я клієнта;","номер телефону;","електронну пошту;","адресу або дані доставки;","інформацію про замовлення;","обрані параметри персоналізованої прикраси;","історію замовлень в особистому кабінеті, якщо така функція використовується;","повідомлення клієнта, надіслані через форми зв’язку або інші канали комунікації."]},{title:"3. Для чого використовуються дані",paragraphs:["Персональні дані використовуються для:"],list:["оформлення та обробки замовлення;","зв’язку з клієнтом щодо замовлення;","уточнення параметрів персоналізованої прикраси;","організації доставки;","надсилання повідомлень про статус замовлення;","обробки звернень щодо повернення, обміну або якості виробу;","забезпечення роботи особистого кабінету, кошика та історії замовлень;","виконання вимог законодавства України."]},{title:"4. Обробка даних при персоналізованому замовленні",paragraphs:["4.1. Якщо клієнт створює прикрасу через конструктор, Aurora Atelier обробляє обрані клієнтом параметри виробу.","4.2. До таких параметрів можуть належати тип прикраси, матеріал, камінь, розмір, гравіювання, комплектація та інші характеристики, необхідні для виконання замовлення.","4.3. Ці дані використовуються виключно для формування, обробки та виконання замовлення."]},{title:"5. Передача даних третім особам",paragraphs:["5.1. Aurora Atelier не продає персональні дані клієнтів третім особам.","5.2. Дані можуть передаватися лише в обсязі, необхідному для виконання замовлення, наприклад службі доставки або платіжному сервісу, якщо такі сервіси використовуються на сайті.","5.3. Також дані можуть бути передані у випадках, передбачених законодавством України."]},{title:"6. Зберігання даних",paragraphs:["6.1. Персональні дані зберігаються протягом строку, необхідного для обробки замовлення, виконання зобов’язань перед клієнтом, ведення обліку замовлень та виконання вимог законодавства.","6.2. Дані можуть бути видалені або знеособлені, якщо вони більше не потрібні для зазначених цілей, крім випадків, коли їх зберігання вимагається законом."]},{title:"7. Захист даних",paragraphs:["7.1. Aurora Atelier вживає розумних організаційних і технічних заходів для захисту персональних даних від випадкової втрати, незаконного доступу, зміни або розголошення.","7.2. Доступ до персональних даних мають лише ті особи або сервіси, яким ці дані потрібні для виконання замовлення або роботи сайту."]},{title:"8. Права клієнта",paragraphs:["Клієнт може звернутися до Aurora Atelier, щоб:"],list:["отримати інформацію про обробку своїх персональних даних;","уточнити або оновити свої дані;","відкликати згоду на обробку персональних даних, якщо така обробка здійснюється на підставі згоди;","попросити видалити дані, якщо їх подальше зберігання не є необхідним для виконання замовлення або вимог законодавства."]},{title:"9. Cookies та технічні дані",paragraphs:["9.1. Сайт може використовувати технічні cookies або подібні технології, необхідні для роботи кошика, авторизації, збереження сесії та коректної роботи інтерфейсу.","9.2. Якщо на сайті будуть використовуватися аналітичні або маркетингові cookies, інформацію про це потрібно додатково зазначити на сайті."]},{title:"10. Зміни до Політики конфіденційності",paragraphs:["10.1. Aurora Atelier може оновлювати цю Політику конфіденційності.","10.2. Актуальна редакція Політики завжди розміщується на цій сторінці."]},{title:"11. Контакти",paragraphs:["З питань обробки, уточнення або видалення персональних даних клієнт може звернутися до Aurora Atelier."],contacts:["Електронна пошта: auroraatelier.mail@gmail.com","Телефон: +38 (099) 000-00-00","Адреса майстерні: м. Харків, вул. Сумська, 10, ТЦ Ave Plaza"]}],en:[{title:"1. General provisions",paragraphs:["1.1. Aurora Atelier respects customer privacy and processes personal data only to the extent necessary for website operation, order placement, customer communication, and order fulfillment.","1.2. By using the website and placing an order, the customer agrees to the terms of this Privacy Policy.","1.3. This Policy applies to the data the customer provides while using the website, registering, placing an order, or contacting Aurora Atelier."]},{title:"2. What data may be collected",paragraphs:["Aurora Atelier may process the following data:"],list:["customer name;","phone number;","email address;","address or delivery details;","order information;","selected parameters of a personalized piece;","order history in the personal account if such functionality is used;","messages sent by the customer through contact forms or other communication channels."]},{title:"3. How the data is used",paragraphs:["Personal data is used for:"],list:["placing and processing an order;","communicating with the customer about the order;","clarifying the parameters of a personalized piece;","arranging delivery;","sending order status updates;","processing requests concerning returns, exchanges, or product quality;","supporting the personal account, cart, and order history;","complying with the requirements of Ukrainian law."]},{title:"4. Processing data for personalized orders",paragraphs:["4.1. If the customer creates a piece through the constructor, Aurora Atelier processes the product parameters selected by the customer.","4.2. Such parameters may include the jewelry type, material, stone, size, engraving, configuration, and other characteristics necessary to fulfill the order.","4.3. This data is used solely for the formation, processing, and fulfillment of the order."]},{title:"5. Transfer of data to third parties",paragraphs:["5.1. Aurora Atelier does not sell customers' personal data to third parties.","5.2. Data may be transferred only to the extent necessary to fulfill the order, for example to a delivery service or a payment service if such services are used on the website.","5.3. Data may also be transferred in cases provided for by Ukrainian law."]},{title:"6. Data retention",paragraphs:["6.1. Personal data is stored for as long as necessary to process the order, perform obligations to the customer, maintain order records, and comply with legal requirements.","6.2. Data may be deleted or anonymized when it is no longer required for those purposes, except where its retention is required by law."]},{title:"7. Data protection",paragraphs:["7.1. Aurora Atelier takes reasonable organizational and technical measures to protect personal data against accidental loss, unlawful access, alteration, or disclosure.","7.2. Personal data is accessible only to those persons or services that need it to fulfill the order or operate the website."]},{title:"8. Customer rights",paragraphs:["A customer may contact Aurora Atelier in order to:"],list:["receive information about the processing of their personal data;","clarify or update their data;","withdraw consent to personal data processing where such processing is based on consent;","request deletion of data if its further storage is not necessary for order fulfillment or legal compliance."]},{title:"9. Cookies and technical data",paragraphs:["9.1. The website may use technical cookies or similar technologies necessary for operation of the cart, authentication, session storage, and proper functioning of the interface.","9.2. If analytical or marketing cookies are used on the website, this should be additionally indicated on the website."]},{title:"10. Changes to the Privacy Policy",paragraphs:["10.1. Aurora Atelier may update this Privacy Policy.","10.2. The current version of the Policy is always published on this page."]},{title:"11. Contacts",paragraphs:["For questions regarding the processing, clarification, or deletion of personal data, the customer may contact Aurora Atelier."],contacts:["Email: auroraatelier.mail@gmail.com","Phone: +38 (099) 000-00-00","Atelier address: Kharkiv, 10 Sumska Street, Ave Plaza"]}]}}};function l(i,a){const r=d[i];return r?{...r,title:r.title[a]||r.title.en,updatedAt:r.updatedAt[a]||r.updatedAt.en,intro:r.intro[a]||r.intro.en,outro:r.outro?r.outro[a]||r.outro.en:"",sections:r.sections[a]||r.sections.en}:null}function h({section:i}){var a,r;return e.jsxs("section",{className:"legal-article-card",children:[e.jsx("h2",{children:i.title}),(i.paragraphs||[]).map(t=>e.jsx("p",{children:t},t)),(a=i.list)!=null&&a.length?e.jsx("ul",{className:"legal-article-list",children:i.list.map(t=>e.jsx("li",{children:t},t))}):null,(r=i.contacts)!=null&&r.length?e.jsx("div",{className:"legal-article-contacts",children:i.contacts.map(t=>e.jsx("p",{children:t},t))}):null]})}function g({pageKey:i}){const{locale:a,toggleLocale:r}=s(),t=l(i,a);return t?e.jsxs(e.Fragment,{children:[e.jsx(n,{}),e.jsxs("div",{className:"app-shell",children:[e.jsx(u,{locale:a,onToggleLocale:r}),e.jsxs("main",{className:"page-main",children:[e.jsx("section",{className:"orders-react-hero legal-hero",children:e.jsxs("div",{className:"container orders-react-heading legal-hero-heading",children:[e.jsx("span",{className:"badge",children:a==="uk"?"Юридична інформація":"Legal information"}),e.jsx("h1",{children:t.title}),e.jsx("p",{children:t.intro})]})}),e.jsx("section",{className:"legal-page-section",children:e.jsxs("div",{className:"container legal-page-grid",children:[e.jsxs("aside",{className:"legal-meta-card",children:[e.jsx("span",{className:"badge subtle",children:a==="uk"?"Актуальна редакція":"Current version"}),e.jsx("h2",{children:t.updatedAt}),t.outro?e.jsx("p",{children:t.outro}):null]}),e.jsx("div",{className:"legal-article-stack",children:t.sections.map(o=>e.jsx(h,{section:o},o.title))})]})})]}),e.jsx(c,{locale:a})]})]}):null}export{g as L};
